#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_VAL 100000 // Maximum value of Ai

int countDistinct(int arr[], int n) {
    bool *seen = (bool *)calloc(MAX_VAL + 1, sizeof(bool)); // Track occurrences
    int distinctCount = 0;

    for (int i = 0; i < n; i++) {
        if (!seen[arr[i]]) { // If element hasn't been seen before
            seen[arr[i]] = true;
            distinctCount++;
        }
    }

    free(seen);
    return distinctCount;
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n;
        scanf("%d", &n);
        int *arr = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }

        printf("%d\n", countDistinct(arr, n));
        free(arr);
    }

    return 0;
}

