const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let inputLines = [];
rl.on('line', (line) => {
    inputLines.push(line.trim());
}).on('close', () => {
    const T = parseInt(inputLines[0]);
    let result = '';

    let index = 1;
    for (let i = 0; i < T; i++) {
        const N = parseInt(inputLines[index]);
        const apples = inputLines[index + 1].split(' ').map(Number);

        // Calculate the number of unique apple counts
        const uniqueApples = new Set(apples);
        result += uniqueApples.size + '\n';

        index += 2;  // Move to the next test case
    }

    process.stdout.write(result);
});
